private void processElement(Element element, PropertyGenerator generator, String annotationName) {
	try {
		String qualifiedName = Elements.getQualifiedName(element);
		AnnotationMirror annotation = getAnnotation(element, annotationName);
		if (qualifiedName != null && annotation != null) {
			List<Object> values = getValues(generator, annotationName, annotation);
			generator.applyToProperties(this.properties, qualifiedName, values);
			this.properties.put(qualifiedName, "");
		}
	}
	catch (Exception ex) {
		throw new IllegalStateException("Error processing configuration meta-data on " + element, ex);
	}
}

private void addToClasses(MetadataReaderFactory metadataReaderFactory,
				@Nullable AutoConfigurationMetadata autoConfigurationMetadata, Collection<String> classNames,
				boolean required) {
			for (String className : classNames) {
				if (!this.classes.containsKey(className)) {
					AutoConfigurationClass autoConfigurationClass = new AutoConfigurationClass(className,
							metadataReaderFactory, autoConfigurationMetadata);
					boolean available = autoConfigurationClass.isAvailable();
					if (required || available) {
						this.classes.put(className, autoConfigurationClass);
					}
					if (available) {
						addToClasses(metadataReaderFactory, autoConfigurationMetadata,
								autoConfigurationClass.getBefore(), false);
						addToClasses(metadataReaderFactory, autoConfigurationMetadata,
								autoConfigurationClass.getAfter(), false);
					}
				}
			}
		}

