FilteredIterableConfigurationPropertiesSource(IterableConfigurationPropertySource source,
			Predicate<ConfigurationPropertyName> filter) {
		super(source, filter);
		@Nullable ConfigurationPropertyName[] filterableNames = getFilterableNames(source);
		if (filterableNames != null) {
			this.filteredNames = new ConfigurationPropertyName[filterableNames.length];
			this.numberOfFilteredNames = 0;
			for (ConfigurationPropertyName name : filterableNames) {
				if (name == null) {
					break;
				}
				if (filter.test(name)) {
					this.filteredNames[this.numberOfFilteredNames++] = name;
				}
			}
		}
	}

private boolean isStringConversionBetter(TypeDescriptor sourceType, TypeDescriptor targetType) {
	if (this.conversionService instanceof ApplicationConversionService applicationConversionService) {
		if (applicationConversionService.isConvertViaObjectSourceType(sourceType, targetType)) {
			// If an ObjectTo... converter is being used then there might be a better
			// StringTo... version
			return true;
		}
	}
	if ((targetType.isArray() || targetType.isCollection()) && !targetType.equals(BYTE_ARRAY)) {
		// StringToArrayConverter / StringToCollectionConverter are better than
		// ObjectToArrayConverter / ObjectToCollectionConverter
		return true;
	}
	return false;
}

@Override
		public boolean matches(TypeDescriptor sourceType, TypeDescriptor targetType) {
			boolean matches = true;
			if (this.converterFactory instanceof ConditionalConverter conditionalConverter) {
				matches = conditionalConverter.matches(sourceType, targetType);
			}
			if (matches) {
				Converter<?, ?> converter = this.converterFactory.getConverter(targetType.getType());
				if (converter instanceof ConditionalConverter conditionalConverter) {
					matches = conditionalConverter.matches(sourceType, targetType);
				}
			}
			return matches;
		}

@SuppressWarnings("unchecked")
	public @Nullable VirtualThreadsInfo getVirtualThreads() {
